/* ==========================================================================
   Historia Argentina 1500–1900 — App
   ==========================================================================
   Scroll spy (Intersection Observer), smooth scroll, timeline interaction.
   No dependencies — vanilla JS only.
   ========================================================================== */

(function () {
  'use strict';

  const PREFIX = '[ScrollSpy]';
  const SECTION_IDS = ['periodo-colonial', 'periodo-revolucion', 'periodo-nacional'];

  // ---------- DOM references ----------

  const sections = SECTION_IDS.map(id => document.getElementById(id)).filter(Boolean);
  const navItems = document.querySelectorAll('.nav-item');
  const navLinks = document.querySelectorAll('.nav-link');
  const timelinePoints = document.querySelectorAll('.timeline-point');

  if (sections.length === 0) {
    console.warn(PREFIX, 'No sections found — scroll spy disabled.');
    return;
  }

  console.debug(PREFIX, `Initialized with ${sections.length} sections:`, sections.map(s => s.id));

  // ---------- State ----------

  let currentSectionId = null;

  // ---------- Helpers ----------

  /**
   * Set the active section across nav and timeline.
   * @param {string} sectionId — ID of the newly active section
   */
  function setActiveSection(sectionId) {
    if (sectionId === currentSectionId) return;
    currentSectionId = sectionId;

    console.debug(PREFIX, 'Active section →', sectionId);

    // Update nav items
    navItems.forEach(item => {
      const link = item.querySelector('.nav-link');
      if (link && link.getAttribute('href') === '#' + sectionId) {
        item.classList.add('nav-item--active');
      } else {
        item.classList.remove('nav-item--active');
      }
    });

    // Update timeline points
    timelinePoints.forEach(point => {
      if (point.dataset.target === sectionId) {
        point.classList.add('timeline-point--active');
      } else {
        point.classList.remove('timeline-point--active');
      }
    });
  }

  // ---------- Scroll Spy via Intersection Observer ----------

  // We use a rootMargin that triggers when a section crosses the top 30% of the viewport.
  // This feels natural: the section is "active" when it occupies the upper portion.
  const observerOptions = {
    root: null,
    rootMargin: '-10% 0px -60% 0px',
    threshold: 0
  };

  const observer = new IntersectionObserver(function (entries) {
    entries.forEach(function (entry) {
      if (entry.isIntersecting) {
        setActiveSection(entry.target.id);
      }
    });
  }, observerOptions);

  sections.forEach(function (section) {
    observer.observe(section);
  });

  // Set initial active section based on what's visible on load
  // (fallback: first section if nothing triggers yet)
  requestAnimationFrame(function () {
    if (!currentSectionId) {
      setActiveSection(SECTION_IDS[0]);
    }
  });

  // ---------- Smooth scroll ----------

  /**
   * Scroll to a section by ID with smooth behavior.
   * @param {string} targetId — section ID to scroll to
   */
  function scrollToSection(targetId) {
    const target = document.getElementById(targetId);
    if (!target) {
      console.warn(PREFIX, 'Scroll target not found:', targetId);
      return;
    }
    target.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }

  // Nav link clicks
  navLinks.forEach(function (link) {
    link.addEventListener('click', function (e) {
      e.preventDefault();
      const href = link.getAttribute('href');
      if (href && href.startsWith('#')) {
        const targetId = href.slice(1);
        scrollToSection(targetId);
        // Update URL hash without jumping
        history.pushState(null, '', href);
      }
    });
  });

  // Timeline point clicks
  timelinePoints.forEach(function (point) {
    point.addEventListener('click', function () {
      var targetId = point.dataset.target;
      if (targetId) {
        scrollToSection(targetId);
        history.pushState(null, '', '#' + targetId);
      }
    });
  });

  // ---------- Handle initial hash ----------

  if (window.location.hash) {
    var hashId = window.location.hash.slice(1);
    if (SECTION_IDS.indexOf(hashId) !== -1) {
      // Delay to let the page settle, then scroll
      setTimeout(function () {
        scrollToSection(hashId);
      }, 100);
    }
  }

  // ---------- Reveal-on-scroll ----------

  revealOnScroll();

  /**
   * Observe elements with `.reveal` and add `.reveal--visible` when they
   * enter the viewport.  Elements already visible at page load get the
   * `.reveal--no-anim` class so they appear instantly without a flash.
   */
  function revealOnScroll() {
    var REVEAL_PREFIX = '[Reveal]';
    var revealEls = document.querySelectorAll('.reveal');

    if (revealEls.length === 0) {
      console.warn(REVEAL_PREFIX, 'No .reveal elements found — reveal system idle.');
      return;
    }

    console.debug(REVEAL_PREFIX, 'Initialized with ' + revealEls.length + ' elements.');

    // ---- Mark elements already in viewport on load (no animation) ----
    var viewportHeight = window.innerHeight || document.documentElement.clientHeight;

    revealEls.forEach(function (el) {
      var rect = el.getBoundingClientRect();
      // Element is "already visible" if its top is above 80% of viewport
      if (rect.top < viewportHeight * 0.8 && rect.bottom > 0) {
        el.classList.add('reveal--no-anim');
        console.debug(REVEAL_PREFIX, 'Already visible (skipping animation):', elLabel(el));
      }
    });

    // ---- Stagger delay for sibling .reveal elements in the same parent ----
    applyStaggerDelays();

    // ---- Intersection Observer for remaining hidden elements ----
    var revealObserverOptions = {
      root: null,
      rootMargin: '0px 0px -15% 0px',  // trigger slightly before fully in view
      threshold: 0.15
    };

    var revealObserver = new IntersectionObserver(function (entries) {
      entries.forEach(function (entry) {
        var el = entry.target;
        // Skip already-revealed elements
        if (el.classList.contains('reveal--visible') || el.classList.contains('reveal--no-anim')) {
          revealObserver.unobserve(el);
          return;
        }
        if (entry.isIntersecting) {
          el.classList.add('reveal--visible');
          console.debug(REVEAL_PREFIX, 'Revealed:', elLabel(el));
          revealObserver.unobserve(el);
        }
      });
    }, revealObserverOptions);

    // Catch-up: for fast/large scrolls that skip past the observation zone,
    // periodically check if any unrevealed elements are above the viewport.
    var catchUpPending = false;
    function catchUpScrolledPast() {
      if (catchUpPending) return;
      catchUpPending = true;
      requestAnimationFrame(function () {
        catchUpPending = false;
        var unrevealed = document.querySelectorAll('.reveal:not(.reveal--visible):not(.reveal--no-anim)');
        unrevealed.forEach(function (el) {
          var rect = el.getBoundingClientRect();
          if (rect.bottom < 0) {
            // Element is entirely above viewport — it was scrolled past
            el.classList.add('reveal--no-anim');
            revealObserver.unobserve(el);
            console.debug(REVEAL_PREFIX, 'Scrolled past (catch-up):', elLabel(el));
          }
        });
      });
    }
    window.addEventListener('scroll', catchUpScrolledPast, { passive: true });

    revealEls.forEach(function (el) {
      // Only observe elements that aren't already visible
      if (!el.classList.contains('reveal--no-anim')) {
        revealObserver.observe(el);
      }
    });
  }

  /**
   * Apply stagger delays to consecutive `.reveal` siblings within the same parent.
   * Each sibling after the first gets an additional 80ms delay.
   */
  function applyStaggerDelays() {
    var parents = new Set();
    document.querySelectorAll('.reveal').forEach(function (el) {
      if (el.parentElement) parents.add(el.parentElement);
    });

    parents.forEach(function (parent) {
      var reveals = parent.querySelectorAll(':scope > .reveal');
      if (reveals.length <= 1) return;
      reveals.forEach(function (el, i) {
        if (i > 0) {
          el.style.setProperty('--reveal-delay', (i * 80) + 'ms');
        }
      });
    });
  }

  /**
   * Return a short label for a DOM element (for debug logging).
   * @param {Element} el
   * @returns {string}
   */
  function elLabel(el) {
    var tag = el.tagName.toLowerCase();
    var cls = el.className.split(' ').filter(function (c) {
      return c && c !== 'reveal' && c !== 'reveal-fade' && c !== 'reveal-slide';
    }).join('.');
    var id = el.id ? '#' + el.id : '';
    return tag + id + (cls ? '.' + cls : '');
  }

  // ---------- Image error fallback ----------

  /**
   * For images inside .card-image, show a sepia-toned fallback with
   * descriptive text when the image fails to load.
   */
  (function initImageFallbacks() {
    var cardImages = document.querySelectorAll('.card-image img');
    cardImages.forEach(function (img) {
      img.addEventListener('error', function () {
        img.classList.add('img-error');
        var wrapper = img.closest('.card-image');
        if (wrapper) {
          // Use a short version of alt text as fallback display
          var altText = img.getAttribute('alt') || 'Imagen no disponible';
          // Truncate to first 60 chars for display
          var displayText = altText.length > 60 ? altText.substring(0, 60) + '…' : altText;
          wrapper.setAttribute('data-fallback-text', displayText);
          wrapper.classList.add('img-fallback');
        }
        console.warn('[Images] Failed to load:', img.src);
      });
    });
    console.debug('[Images] Fallback handlers set for', cardImages.length, 'card images.');
  })();

})();

/* ==========================================================================
   Historia Argentina 1500–1900 — Estilos Base
   ==========================================================================
   Paleta: sepia/pergamino con acentos celeste y blanco (D004)
   Tipografía: Playfair Display (títulos), Source Serif 4 (citas), Lato (cuerpo)
   Layout: Timeline vertical con secciones full-width
   ========================================================================== */

/* ---------- Reset & Foundations ---------- */

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: 'Lato', 'Helvetica Neue', sans-serif;
  font-weight: 300;
  line-height: 1.7;
  color: var(--color-text);
  background-color: var(--color-bg);
  overflow-x: hidden;
}

img, video {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

ul, ol {
  list-style: none;
}

/* ---------- CSS Custom Properties ---------- */

:root {
  /* Paleta sepia / pergamino */
  --color-bg:            #f5f0e8;
  --color-bg-warm:       #ede6d6;
  --color-text:          #3b2f20;
  --color-text-muted:    #7a6b5a;
  --color-sepia-light:   #f0e8d4;
  --color-sepia-mid:     #d4c4a0;
  --color-sepia-dark:    #8b7355;

  /* Acentos nacionales */
  --color-celeste:       #74acdf;
  --color-celeste-soft:  #a8cce8;
  --color-celeste-deep:  #4a8ab5;
  --color-blanco:        #ffffff;

  /* Acentos por período */
  --color-colonial:      #a08060;
  --color-revolucion:    #74acdf;
  --color-nacional:      #8b6b4a;

  /* Superficies */
  --color-card-bg:       #faf7f0;
  --color-card-border:   #e0d5c0;
  --color-divider:       #d4c4a0;

  /* Sombras */
  --shadow-soft:         0 2px 12px rgba(59, 47, 32, 0.08);
  --shadow-card:         0 1px 4px rgba(59, 47, 32, 0.06), 0 4px 16px rgba(59, 47, 32, 0.04);
  --shadow-elevated:     0 4px 24px rgba(59, 47, 32, 0.12);

  /* Tipografía */
  --font-display:        'Playfair Display', 'Georgia', serif;
  --font-body:           'Lato', 'Helvetica Neue', sans-serif;
  --font-serif:          'Source Serif 4', 'Georgia', serif;

  /* Espaciado */
  --space-xs:   0.25rem;
  --space-sm:   0.5rem;
  --space-md:   1rem;
  --space-lg:   2rem;
  --space-xl:   3rem;
  --space-2xl:  5rem;
  --space-3xl:  8rem;

  /* Layout */
  --content-width:       72rem;
  --content-narrow:      48rem;
  --nav-height:          3.5rem;

  /* Transiciones */
  --ease-out:            cubic-bezier(0.23, 1, 0.32, 1);
  --duration-fast:       150ms;
  --duration-normal:     300ms;
  --duration-slow:       600ms;
}

/* ---------- Textura de fondo global ---------- */

body::before {
  content: '';
  position: fixed;
  inset: 0;
  background-image:
    radial-gradient(ellipse at 20% 50%, rgba(160, 128, 96, 0.04) 0%, transparent 60%),
    radial-gradient(ellipse at 80% 20%, rgba(116, 172, 223, 0.03) 0%, transparent 50%);
  pointer-events: none;
  z-index: 0;
}

/* ---------- Header ---------- */

.site-header {
  position: relative;
  padding: var(--space-3xl) var(--space-lg) var(--space-2xl);
  text-align: center;
  background:
    linear-gradient(180deg, var(--color-bg-warm) 0%, var(--color-bg) 100%);
  border-bottom: 1px solid var(--color-divider);
  z-index: 1;
}

.site-header::after {
  content: '';
  position: absolute;
  bottom: -1px;
  left: 50%;
  transform: translateX(-50%);
  width: 6rem;
  height: 3px;
  background: linear-gradient(90deg, transparent, var(--color-celeste), transparent);
}

.header-inner {
  max-width: var(--content-narrow);
  margin: 0 auto;
}

.header-kicker {
  font-family: var(--font-body);
  font-size: 0.8rem;
  font-weight: 400;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--color-text-muted);
  margin-bottom: var(--space-md);
}

.header-title {
  font-family: var(--font-display);
  font-size: clamp(2.2rem, 5vw, 3.8rem);
  font-weight: 900;
  line-height: 1.15;
  color: var(--color-text);
  margin-bottom: var(--space-lg);
}

.title-years {
  display: block;
  font-weight: 400;
  font-style: italic;
  font-size: 0.65em;
  color: var(--color-sepia-dark);
  margin-top: var(--space-xs);
}

.header-subtitle {
  font-family: var(--font-serif);
  font-size: 1.15rem;
  line-height: 1.8;
  color: var(--color-text-muted);
  max-width: 36rem;
  margin: 0 auto;
}

.alberdi-name {
  font-weight: 600;
  color: var(--color-text);
  white-space: nowrap;
}

/* ---------- Navegación ---------- */

.site-nav {
  position: sticky;
  top: 0;
  z-index: 100;
  background: rgba(245, 240, 232, 0.92);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--color-divider);
  padding: 0 var(--space-md);
}

.nav-list {
  display: flex;
  justify-content: center;
  gap: 0;
  max-width: var(--content-width);
  margin: 0 auto;
}

.nav-item {
  flex: 1;
  max-width: 16rem;
}

.nav-link {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.15rem;
  padding: var(--space-sm) var(--space-md);
  border-bottom: 3px solid transparent;
  transition: border-color var(--duration-normal) var(--ease-out),
              background var(--duration-normal) var(--ease-out);
}

.nav-link:hover {
  background: rgba(160, 128, 96, 0.06);
  border-bottom-color: var(--color-sepia-mid);
}

.nav-item--active .nav-link {
  border-bottom-color: var(--color-celeste);
}

.nav-years {
  font-family: var(--font-display);
  font-size: 0.85rem;
  font-weight: 700;
  color: var(--color-text);
}

.nav-label {
  font-size: 0.7rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--color-text-muted);
}

/* ---------- Secciones de período ---------- */

.site-main {
  position: relative;
  z-index: 1;
}

.period {
  position: relative;
  padding: var(--space-3xl) var(--space-lg);
  border-bottom: 1px solid var(--color-divider);
}

.period-header {
  text-align: center;
  max-width: var(--content-narrow);
  margin: 0 auto var(--space-2xl);
}

.period-years {
  display: inline-block;
  font-family: var(--font-display);
  font-size: 0.85rem;
  font-weight: 700;
  letter-spacing: 0.15em;
  color: var(--color-text-muted);
  padding: var(--space-xs) var(--space-md);
  border: 1px solid var(--color-divider);
  border-radius: 2rem;
  margin-bottom: var(--space-md);
}

.period-title {
  font-family: var(--font-display);
  font-size: clamp(1.8rem, 3.5vw, 2.8rem);
  font-weight: 700;
  line-height: 1.2;
  color: var(--color-text);
  margin-bottom: var(--space-sm);
}

.period-scope {
  font-family: var(--font-body);
  font-size: 0.8rem;
  font-weight: 400;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-text-muted);
}

.period-body {
  max-width: var(--content-width);
  margin: 0 auto;
}

.period-intro {
  max-width: var(--content-narrow);
  margin: 0 auto var(--space-2xl);
}

.period-intro p {
  font-family: var(--font-serif);
  font-size: 1.1rem;
  line-height: 1.85;
  color: var(--color-text);
}

/* ---------- Acentos por período ---------- */

.period--colonial {
  background: linear-gradient(180deg, var(--color-bg) 0%, rgba(160, 128, 96, 0.04) 50%, var(--color-bg) 100%);
}

.period--colonial .period-years {
  border-color: var(--color-colonial);
  color: var(--color-colonial);
}

.period--revolucion {
  background: linear-gradient(180deg, var(--color-bg) 0%, rgba(116, 172, 223, 0.06) 50%, var(--color-bg) 100%);
}

.period--revolucion .period-years {
  border-color: var(--color-celeste);
  color: var(--color-celeste-deep);
}

.period--nacional {
  background: linear-gradient(180deg, var(--color-bg) 0%, rgba(139, 107, 74, 0.04) 50%, var(--color-bg) 100%);
}

.period--nacional .period-years {
  border-color: var(--color-nacional);
  color: var(--color-nacional);
}

/* ---------- Sección destacada (1800–1860) ---------- */

.period--featured {
  padding-top: calc(var(--space-3xl) + 2rem);
}

.period--featured::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 4px;
  background: linear-gradient(90deg,
    transparent 10%,
    var(--color-celeste-soft) 30%,
    var(--color-celeste) 50%,
    var(--color-celeste-soft) 70%,
    transparent 90%
  );
}

.period--featured .period-title {
  font-size: clamp(2rem, 4vw, 3.2rem);
}

.period-featured-badge {
  position: absolute;
  top: var(--space-lg);
  left: 50%;
  transform: translateX(-50%);
  padding: var(--space-xs) var(--space-lg);
  background: var(--color-celeste);
  color: var(--color-blanco);
  font-family: var(--font-body);
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  border-radius: 2rem;
  box-shadow: 0 2px 8px rgba(116, 172, 223, 0.3);
}

/* ---------- Cita de Alberdi ---------- */

.alberdi-quote {
  margin: var(--space-xl) auto;
  padding: var(--space-lg) var(--space-xl);
  max-width: 36rem;
  border-left: 3px solid var(--color-celeste);
  background: rgba(116, 172, 223, 0.04);
  border-radius: 0 4px 4px 0;
}

.alberdi-quote p {
  font-family: var(--font-serif);
  font-size: 1.3rem;
  font-style: italic;
  line-height: 1.6;
  color: var(--color-text);
  margin-bottom: var(--space-sm);
}

.alberdi-quote cite {
  font-family: var(--font-body);
  font-size: 0.8rem;
  font-style: normal;
  color: var(--color-text-muted);
  display: block;
}

/* ---------- Grid de eventos (placeholder) ---------- */

.events-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(min(100%, 20rem), 1fr));
  gap: var(--space-lg);
  margin-top: var(--space-xl);
}

.event-card {
  position: relative;
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  border-radius: 6px;
  padding: var(--space-lg);
  box-shadow: var(--shadow-card);
  transition: box-shadow var(--duration-normal) var(--ease-out),
              transform var(--duration-normal) var(--ease-out);
}

.event-card:hover {
  box-shadow: var(--shadow-elevated);
  transform: translateY(-2px);
}

.event-card--placeholder {
  opacity: 0.85;
}

.event-card__year {
  display: inline-block;
  font-family: var(--font-display);
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  color: var(--color-sepia-dark);
  padding: 2px var(--space-sm);
  border: 1px solid var(--color-sepia-mid);
  border-radius: 3px;
  margin-bottom: var(--space-sm);
}

.event-card__title {
  font-family: var(--font-display);
  font-size: 1.15rem;
  font-weight: 700;
  line-height: 1.3;
  color: var(--color-text);
  margin-bottom: var(--space-sm);
}

.event-card__excerpt {
  font-family: var(--font-serif);
  font-size: 0.95rem;
  line-height: 1.65;
  color: var(--color-text-muted);
}

/* Acentos en cards por período */

.period--colonial .event-card {
  border-top: 2px solid rgba(160, 128, 96, 0.3);
}

.period--revolucion .event-card {
  border-top: 2px solid rgba(116, 172, 223, 0.4);
}

.period--nacional .event-card {
  border-top: 2px solid rgba(139, 107, 74, 0.3);
}

/* ---------- Timeline lateral ---------- */

.timeline-aside {
  position: fixed;
  left: var(--space-lg);
  top: 50%;
  transform: translateY(-50%);
  z-index: 90;
  pointer-events: none;
}

.timeline-track {
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2.5rem;
  padding: var(--space-lg) 0;
  pointer-events: auto;
}

.timeline-line {
  position: absolute;
  top: var(--space-lg);
  bottom: var(--space-lg);
  left: 50%;
  width: 2px;
  background: var(--color-sepia-mid);
  opacity: 0.4;
  transform: translateX(-50%);
}

.timeline-point {
  position: relative;
  z-index: 1;
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  background: none;
  border: none;
  cursor: pointer;
  padding: var(--space-xs);
  font-family: inherit;
}

.timeline-point__dot {
  display: block;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  border: 2px solid var(--color-sepia-mid);
  background: var(--color-bg);
  transition:
    background var(--duration-normal) var(--ease-out),
    border-color var(--duration-normal) var(--ease-out),
    transform var(--duration-normal) var(--ease-out),
    box-shadow var(--duration-normal) var(--ease-out);
}

.timeline-point__label {
  font-family: var(--font-display);
  font-size: 0.65rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  color: var(--color-text-muted);
  white-space: nowrap;
  opacity: 0;
  transform: translateX(-4px);
  transition:
    opacity var(--duration-normal) var(--ease-out),
    transform var(--duration-normal) var(--ease-out);
}

/* Show label on hover */
.timeline-point:hover .timeline-point__label {
  opacity: 1;
  transform: translateX(0);
}

.timeline-point:hover .timeline-point__dot {
  border-color: var(--color-sepia-dark);
  transform: scale(1.2);
}

/* Active state */
.timeline-point--active .timeline-point__dot {
  background: var(--color-celeste);
  border-color: var(--color-celeste);
  box-shadow: 0 0 0 4px rgba(116, 172, 223, 0.2);
  transform: scale(1.15);
}

.timeline-point--active .timeline-point__label {
  opacity: 1;
  transform: translateX(0);
  color: var(--color-celeste-deep);
}

/* ---------- Footer ---------- */

.site-footer {
  position: relative;
  padding: var(--space-2xl) var(--space-lg) var(--space-xl);
  background: var(--color-bg-warm);
  border-top: 1px solid var(--color-divider);
  z-index: 1;
}

.footer-inner {
  max-width: var(--content-narrow);
  margin: 0 auto;
  text-align: center;
}

.footer-alberdi {
  margin-bottom: var(--space-xl);
  padding-bottom: var(--space-xl);
  border-bottom: 1px solid var(--color-divider);
}

.footer-epigraph {
  font-family: var(--font-serif);
  font-size: 1.15rem;
  font-style: italic;
  line-height: 1.7;
  color: var(--color-text);
  margin-bottom: var(--space-sm);
}

.footer-cite {
  font-family: var(--font-body);
  font-size: 0.8rem;
  font-style: normal;
  color: var(--color-text-muted);
}

.footer-credits p {
  font-family: var(--font-body);
  font-size: 0.85rem;
  color: var(--color-text-muted);
  margin-bottom: var(--space-xs);
}

.footer-note {
  font-size: 0.75rem !important;
  max-width: 32rem;
  margin-left: auto;
  margin-right: auto;
}

.footer-hilo {
  margin-top: var(--space-md) !important;
  font-size: 0.8rem !important;
}

.footer-hilo strong {
  color: var(--color-text);
  font-weight: 700;
}

/* ---------- Responsivo ---------- */

@media (max-width: 48rem) {
  .timeline-aside {
    display: none;
  }

  .site-header {
    padding: var(--space-2xl) var(--space-md) var(--space-xl);
  }

  .period {
    padding: var(--space-2xl) var(--space-md);
  }

  .nav-link {
    padding: var(--space-sm) var(--space-xs);
  }

  .nav-label {
    font-size: 0.6rem;
  }

  .nav-years {
    font-size: 0.75rem;
  }

  .events-grid {
    grid-template-columns: 1fr;
  }

  .alberdi-quote {
    padding: var(--space-md) var(--space-lg);
    margin-left: 0;
    margin-right: 0;
  }
}

@media (max-width: 30rem) {
  .nav-list {
    flex-direction: column;
    align-items: center;
    gap: 0;
  }

  .nav-item {
    width: 100%;
    max-width: none;
  }

  .nav-link {
    flex-direction: row;
    justify-content: center;
    gap: var(--space-sm);
    padding: var(--space-sm) var(--space-md);
  }
}

/* ---------- Reveal-on-scroll animations ---------- */

/*
 * Base: elements start invisible. `.reveal--visible` transitions them in.
 * Variants: `.reveal-fade` (opacity only), `.reveal-slide` (opacity + translateY).
 * Respects prefers-reduced-motion: skips animation entirely.
 */

.reveal {
  opacity: 0;
  will-change: opacity, transform;
  transition:
    opacity var(--reveal-duration, 400ms) var(--ease-out) var(--reveal-delay, 0ms),
    transform var(--reveal-duration, 400ms) var(--ease-out) var(--reveal-delay, 0ms);
}

/* Variant: slide up from below */
.reveal.reveal-slide {
  transform: translateY(24px);
}

/* Visible state — applied by JS Intersection Observer */
.reveal.reveal--visible {
  opacity: 1;
  transform: translateY(0);
}

/* Elements that were already visible on load — no animation */
.reveal.reveal--no-anim {
  opacity: 1;
  transform: none;
  transition: none;
  will-change: auto;
}

/* Accessibility: skip all reveal animations for users who prefer reduced motion */
@media (prefers-reduced-motion: reduce) {
  .reveal {
    opacity: 1;
    transform: none;
    transition: none;
    will-change: auto;
  }
}

/* ---------- Utilidades ---------- */

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* ---------- Cards de certeza — Sistema de niveles (S03) ---------- */

/*
 * Three card variants differentiated by border, color accent, and layout:
 *   .card-hecho  — green-tinted, solid style, source citation footer
 *   .card-opinion — blue-tinted, blockquote interior with attribution
 *   .card-rumor  — amber-tinted, "Rumor" badge, italic text, origin note
 *
 * All three inherit from .event-card base and add a left border accent,
 * a top indicator bar, and type-specific inner styling.
 */

:root {
  /* Certeza accent palette */
  --certeza-hecho:       #4a7c59;
  --certeza-hecho-soft:  rgba(74, 124, 89, 0.08);
  --certeza-hecho-mid:   rgba(74, 124, 89, 0.18);

  --certeza-opinion:     #4a6fa5;
  --certeza-opinion-soft: rgba(74, 111, 165, 0.07);
  --certeza-opinion-mid: rgba(74, 111, 165, 0.16);

  --certeza-rumor:       #b8860b;
  --certeza-rumor-soft:  rgba(184, 134, 11, 0.07);
  --certeza-rumor-mid:   rgba(184, 134, 11, 0.15);
}

/* ---- Grid override for certeza cards ---- */

.events-grid--certeza {
  grid-template-columns: repeat(auto-fill, minmax(min(100%, 22rem), 1fr));
  gap: var(--space-xl);
  align-items: start;
}

/* ---- Shared certeza card structure ---- */

.card-hecho,
.card-opinion,
.card-rumor {
  border-top: none;
  border-left: 4px solid transparent;
  padding: 0;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

/* ---- Certeza indicator bar (top of card) ---- */

.card-certeza-indicator {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  padding: var(--space-sm) var(--space-lg);
  font-family: var(--font-body);
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.card-certeza-icon {
  font-size: 0.9rem;
  line-height: 1;
}

.card-certeza-label {
  line-height: 1;
}

/* ---- Image placeholder ---- */

.card-image-placeholder {
  width: 100%;
  aspect-ratio: 16 / 9;
  background: var(--color-sepia-light);
  display: flex;
  align-items: center;
  justify-content: center;
  border-top: 1px solid var(--color-card-border);
  border-bottom: 1px solid var(--color-card-border);
  overflow: hidden;
}

.card-image-placeholder__text {
  font-family: var(--font-body);
  font-size: 0.75rem;
  font-weight: 400;
  color: var(--color-text-muted);
  letter-spacing: 0.05em;
  text-transform: uppercase;
  opacity: 0.6;
}

/* ---- Card images (real historical images) ---- */

.card-image {
  width: 100%;
  max-height: 220px;
  overflow: hidden;
  border-top: 1px solid var(--color-card-border);
  border-bottom: 1px solid var(--color-card-border);
  background-color: var(--color-sepia-light);
  position: relative;
}

.card-image img {
  width: 100%;
  height: 100%;
  max-height: 220px;
  object-fit: cover;
  display: block;
  transition: opacity var(--duration-normal) var(--ease-out);
}

/* Fallback for broken image loads */
.card-image img.img-error {
  opacity: 0;
}

.card-image.img-fallback::after {
  content: attr(data-fallback-text);
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-body);
  font-size: 0.75rem;
  font-weight: 400;
  color: var(--color-text-muted);
  letter-spacing: 0.05em;
  text-transform: uppercase;
  opacity: 0.6;
  background-color: var(--color-sepia-light);
  text-align: center;
  padding: var(--space-md);
}

/* ---- Card inner content spacing ---- */

.card-hecho .event-card__year,
.card-opinion .event-card__year,
.card-rumor .event-card__year {
  margin: var(--space-lg) var(--space-lg) var(--space-sm);
}

.card-hecho .event-card__title,
.card-opinion .event-card__title,
.card-rumor .event-card__title {
  padding: 0 var(--space-lg);
  margin-bottom: var(--space-sm);
}

.card-hecho .event-card__excerpt,
.card-opinion .event-card__excerpt,
.card-rumor .event-card__excerpt {
  padding: 0 var(--space-lg);
  margin-bottom: var(--space-lg);
}

/* ============================================================
   CARD-HECHO — Hecho documentado
   ============================================================ */

.card-hecho {
  border-left-color: var(--certeza-hecho);
  background: linear-gradient(
    135deg,
    var(--color-card-bg) 0%,
    var(--certeza-hecho-soft) 100%
  );
}

.card-hecho .card-certeza-indicator {
  background: var(--certeza-hecho-mid);
  color: var(--certeza-hecho);
}

.card-hecho .event-card__year {
  border-color: var(--certeza-hecho);
  color: var(--certeza-hecho);
}

/* Source citation footer */

.card-source {
  display: flex;
  align-items: flex-start;
  gap: var(--space-sm);
  padding: var(--space-md) var(--space-lg);
  margin-top: auto;
  border-top: 1px solid var(--certeza-hecho-mid);
  background: var(--certeza-hecho-soft);
}

.card-source__icon {
  font-size: 0.85rem;
  line-height: 1.4;
  flex-shrink: 0;
}

.card-source cite {
  font-family: var(--font-body);
  font-size: 0.78rem;
  font-style: normal;
  line-height: 1.5;
  color: var(--color-text-muted);
}

/* ============================================================
   CARD-OPINION — Opinión atribuida
   ============================================================ */

.card-opinion {
  border-left-color: var(--certeza-opinion);
  background: linear-gradient(
    135deg,
    var(--color-card-bg) 0%,
    var(--certeza-opinion-soft) 100%
  );
}

.card-opinion .card-certeza-indicator {
  background: var(--certeza-opinion-mid);
  color: var(--certeza-opinion);
}

.card-opinion .event-card__year {
  border-color: var(--certeza-opinion);
  color: var(--certeza-opinion);
}

/* Blockquote interior */

.card-opinion__quote {
  margin: 0 var(--space-lg) var(--space-lg);
  padding: var(--space-md) var(--space-lg);
  border-left: 3px solid var(--certeza-opinion);
  background: var(--certeza-opinion-soft);
  border-radius: 0 4px 4px 0;
  position: relative;
}

.card-opinion__quote::before {
  content: '\201C';
  position: absolute;
  top: -0.15em;
  left: 0.25em;
  font-family: var(--font-display);
  font-size: 2.8rem;
  line-height: 1;
  color: var(--certeza-opinion);
  opacity: 0.25;
  pointer-events: none;
}

.card-opinion__quote p {
  font-family: var(--font-serif);
  font-size: 1rem;
  font-style: italic;
  line-height: 1.7;
  color: var(--color-text);
  margin-bottom: var(--space-sm);
  position: relative;
  z-index: 1;
}

.card-opinion__attribution {
  font-family: var(--font-body);
  font-size: 0.78rem;
  line-height: 1.5;
  color: var(--color-text-muted);
}

.card-opinion__author {
  font-weight: 700;
  color: var(--certeza-opinion);
}

.card-opinion__context {
  display: block;
  margin-top: 2px;
}

.card-opinion__context em {
  font-style: italic;
}

/* ============================================================
   CARD-RUMOR — Rumor / Especulación
   ============================================================ */

.card-rumor {
  border-left-color: var(--certeza-rumor);
  background: linear-gradient(
    135deg,
    var(--color-card-bg) 0%,
    var(--certeza-rumor-soft) 100%
  );
}

.card-rumor .card-certeza-indicator {
  background: var(--certeza-rumor-mid);
  color: var(--certeza-rumor);
}

.card-rumor .event-card__year {
  border-color: var(--certeza-rumor);
  color: var(--certeza-rumor);
}

/* "Rumor" badge */

.card-certeza-badge-rumor {
  display: inline-block;
  font-family: var(--font-body);
  font-size: 0.65rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  padding: 2px 10px;
  border-radius: 3px;
  background: var(--certeza-rumor);
  color: #fff;
  line-height: 1.4;
}

/* Italic text for rumor cards */

.card-rumor__text {
  font-style: italic;
}

/* Origin/provenance footer */

.card-rumor__origin {
  display: flex;
  align-items: flex-start;
  gap: var(--space-sm);
  padding: var(--space-md) var(--space-lg);
  margin-top: auto;
  border-top: 1px dashed var(--certeza-rumor-mid);
  background: var(--certeza-rumor-soft);
}

.card-rumor__origin-icon {
  font-size: 0.85rem;
  line-height: 1.4;
  flex-shrink: 0;
}

.card-rumor__origin-text {
  font-family: var(--font-body);
  font-size: 0.78rem;
  line-height: 1.55;
  color: var(--color-text-muted);
  font-style: normal;
}

.card-rumor__origin-text strong {
  color: var(--certeza-rumor);
  font-weight: 700;
}

/* ---- Hover enhancements for certeza cards ---- */

.card-hecho:hover {
  border-left-color: var(--certeza-hecho);
  box-shadow: var(--shadow-elevated), inset 0 0 0 1px var(--certeza-hecho-mid);
}

.card-opinion:hover {
  border-left-color: var(--certeza-opinion);
  box-shadow: var(--shadow-elevated), inset 0 0 0 1px var(--certeza-opinion-mid);
}

.card-rumor:hover {
  border-left-color: var(--certeza-rumor);
  box-shadow: var(--shadow-elevated), inset 0 0 0 1px var(--certeza-rumor-mid);
}

/* ---- Responsive adjustments for certeza cards ---- */

@media (max-width: 48rem) {
  .events-grid--certeza {
    grid-template-columns: 1fr;
    gap: var(--space-lg);
  }

  .card-opinion__quote {
    margin-left: var(--space-md);
    margin-right: var(--space-md);
  }

  .card-hecho .event-card__year,
  .card-opinion .event-card__year,
  .card-rumor .event-card__year,
  .card-hecho .event-card__title,
  .card-opinion .event-card__title,
  .card-rumor .event-card__title,
  .card-hecho .event-card__excerpt,
  .card-opinion .event-card__excerpt,
  .card-rumor .event-card__excerpt {
    padding-left: var(--space-md);
    padding-right: var(--space-md);
  }
}

/* ==========================================================================
   Animated Colonial Timeline — T02: CSS animation element
   ==========================================================================
   A horizontal timeline bar spanning 1500–1807 with key date markers
   that animate in sequence using CSS keyframes. Respects prefers-reduced-motion.
   Scoped to .colonial-timeline — does not affect other sections.
   ========================================================================== */

.colonial-timeline {
  max-width: 800px;
  margin: var(--space-2xl) auto var(--space-lg);
  padding: var(--space-xl) var(--space-lg);
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  border-radius: 6px;
  box-shadow: var(--shadow-card);
  text-align: center;
}

.colonial-timeline__title {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--color-text);
  margin-bottom: var(--space-xs);
}

.colonial-timeline__subtitle {
  font-family: var(--font-body);
  font-size: 0.78rem;
  font-weight: 400;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--color-text-muted);
  margin-bottom: var(--space-xl);
}

.colonial-timeline__track {
  position: relative;
  height: 4px;
  background: var(--color-sepia-mid);
  border-radius: 2px;
  margin: 2.5rem 1rem 3.5rem;
}

/* Animated progress bar */
.colonial-timeline__progress {
  position: absolute;
  top: 0;
  left: 0;
  height: 100%;
  width: 0;
  background: linear-gradient(90deg, var(--color-colonial), var(--color-sepia-dark));
  border-radius: 2px;
  animation: timeline-fill 2.5s var(--ease-out) forwards;
  animation-play-state: paused;
}

/* Start animation when parent becomes visible via IntersectionObserver */
.colonial-timeline.reveal--visible .colonial-timeline__progress {
  animation-play-state: running;
}

@keyframes timeline-fill {
  from { width: 0; }
  to { width: 100%; }
}

/* Individual date markers */
.colonial-timeline__marker {
  position: absolute;
  left: var(--marker-pos);
  top: 50%;
  transform: translate(-50%, -50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  z-index: 2;
}

.colonial-timeline__dot {
  display: block;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: var(--color-bg);
  border: 3px solid var(--color-sepia-mid);
  transition: border-color var(--duration-normal) var(--ease-out),
              background var(--duration-normal) var(--ease-out),
              transform var(--duration-normal) var(--ease-out);
  opacity: 0;
  transform: scale(0);
}

/* Staggered dot entrance: each marker appears after the progress bar reaches it */
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(2) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 0.2s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(3) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 0.55s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(4) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 0.85s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(5) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 1.1s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(6) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 2.0s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(7) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 2.3s forwards;
}

@keyframes marker-pop {
  0% {
    opacity: 0;
    transform: scale(0);
  }
  60% {
    opacity: 1;
    transform: scale(1.3);
  }
  100% {
    opacity: 1;
    transform: scale(1);
    background: var(--color-colonial);
    border-color: var(--color-colonial);
  }
}

/* Labels under dots */
.colonial-timeline__label {
  position: absolute;
  top: 1.2rem;
  left: 50%;
  transform: translateX(-50%);
  white-space: nowrap;
  font-family: var(--font-display);
  font-size: 0.72rem;
  font-weight: 700;
  line-height: 1.3;
  color: var(--color-text);
  text-align: center;
  opacity: 0;
}

.colonial-timeline__label small {
  display: block;
  font-family: var(--font-body);
  font-size: 0.62rem;
  font-weight: 400;
  color: var(--color-text-muted);
  white-space: nowrap;
}

/* Labels appear with dots */
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(2) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 0.4s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(3) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 0.75s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(4) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 1.05s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(5) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 1.3s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(6) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 2.2s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(7) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 2.5s forwards;
}

@keyframes label-fade {
  from {
    opacity: 0;
    transform: translateX(-50%) translateY(4px);
  }
  to {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
  }
}

/* Hover on markers */
.colonial-timeline__marker:hover .colonial-timeline__dot {
  border-color: var(--color-text) !important;
  transform: scale(1.3);
}

/* ---- Responsive: colonial timeline ---- */

@media (max-width: 48rem) {
  .colonial-timeline {
    margin: var(--space-xl) auto var(--space-md);
    padding: var(--space-lg) var(--space-md);
  }

  .colonial-timeline__track {
    margin: 2rem 0.5rem 3rem;
  }

  .colonial-timeline__label {
    font-size: 0.6rem;
  }

  .colonial-timeline__label small {
    font-size: 0.5rem;
  }

  .colonial-timeline__dot {
    width: 10px;
    height: 10px;
    border-width: 2px;
  }
}

@media (max-width: 30rem) {
