/* ==========================================================================
   Responsive Video Wrapper — T02: Infrastructure for video embeds
   ==========================================================================
   Ready for YouTube/Vimeo iframe embeds. Use: <div class="responsive-video"><iframe ...></div>
   ========================================================================== */

.responsive-video {
  max-width: 800px;
  margin: var(--space-2xl) auto var(--space-lg);
  text-align: center;
}

.responsive-video__heading {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--color-text);
  margin-bottom: var(--space-xs);
}

.responsive-video__caption {
  font-family: var(--font-body);
  font-size: 0.82rem;
  color: var(--color-text-muted);
  margin-bottom: var(--space-md);
}

.responsive-video__wrapper {
  position: relative;
  aspect-ratio: 16 / 9;
  width: 100%;
  background: var(--color-sepia-light);
  border-radius: 6px;
  overflow: hidden;
  box-shadow: var(--shadow-card);
}

.responsive-video__wrapper iframe {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  border: 0;
}

@media (prefers-reduced-motion: reduce) {
  .responsive-video__wrapper iframe {
    /* Autoplay suppressed by browser; no additional action needed */
  }
}

/* =====================================================
   SUB-PERIOD STRUCTURE — #periodo-revolucion
   Added: T07 (M003/S01)
   ===================================================== */

/* Sub-period wrapper — groups cards for one historical phase */
.sub-period {
  margin-bottom: var(--space-3xl);
}

/* Sub-period title (h3 inside each .sub-period) */
.sub-period__title {
  font-family: var(--font-serif);
  font-size: clamp(1.15rem, 2.5vw, 1.5rem);
  font-weight: 600;
  color: var(--color-celeste-deep);
  letter-spacing: 0.01em;
  margin: 0 0 var(--space-xl) 0;
  padding-bottom: var(--space-sm);
  border-bottom: 2px solid rgba(116, 172, 223, 0.3);
  position: relative;
  display: flex;
  align-items: center;
  gap: var(--space-sm);
}

/* Decorative left accent bar on sub-period title */
.sub-period__title::before {
  content: '';
  display: inline-block;
  width: 4px;
  height: 1.1em;
  background: var(--color-celeste);
  border-radius: 2px;
  flex-shrink: 0;
}

/* Alberdi quote block between sub-periods */
.alberdi-quote {
  margin: var(--space-2xl) auto;
  max-width: var(--content-narrow);
  text-align: center;
}

/* Divider between sub-periods and connecting quote */
.sub-period + .alberdi-quote {
  padding-top: var(--space-xl);
  border-top: 1px solid rgba(116, 172, 223, 0.15);
}

/* Responsive: stack sub-period title on narrow viewports */
@media (max-width: 640px) {
  .sub-period__title {
    font-size: 1.05rem;
  }

  .sub-period {
    margin-bottom: var(--space-2xl);
  }
}

